def run(*args: str) -> str:
result = subprocess.run(
[sys.executable, *args],
check=False,
capture_output=True,
text=True,
cwd=ROOT,
)
if result.returncode != 0:
raise RuntimeError(result.stderr.strip() or result.stdout.strip())
return result.stdout.strip()

def load_prompt(args: argparse.Namespace) -> str:
if args.prompt is not None:
return args.prompt
if args.prompt_file is not None:
return Path(args.prompt_file).read_text(encoding="utf-8")
raise SystemExit("provide --prompt or --prompt-file")

prompt = load_prompt(args)
js = f"""
(() => {{
const editor = document.querySelector('.ql-editor');
if (!editor) return 'no-editor';
editor.focus();
editor.innerHTML = '';
const text = {prompt!r};
editor.textContent = text;
editor.dispatchEvent(new InputEvent('input', {{
bubbles: true,
inputType: 'insertText',
data: text
}}));
const opts = {{
key: 'Enter',
code: 'Enter',
keyCode: 13,
which: 13,
bubbles: true,
cancelable: true
}};
editor.dispatchEvent(new KeyboardEvent('keydown', opts));
editor.dispatchEvent(new KeyboardEvent('keypress', opts));
editor.dispatchEvent(new KeyboardEvent('keyup', opts));
return editor.innerText;
}})();
"""
print(chrome_js(js))

def main() -> None:
js = """
(() => {
const items = [...document.querySelectorAll(
'.chat-message-container.left .chat-base-message-container.chat-message'
)];
if (!items.length) return '';
return items[items.length - 1].innerText || '';
})();
"""
print(chrome_js(js))

def run_applescript(script: str) -> str:
result = subprocess.run(
["osascript", "-e", script],
check=False,
capture_output=True,
text=True,
)
if result.returncode != 0:
raise RuntimeError(result.stderr.strip())
return result.stdout.strip()

def chrome_js(js: str) -> str:
encoded = base64.b64encode(js.encode("utf-8")).decode("ascii")
wrapped = (
"eval(new TextDecoder('utf-8').decode("
f"Uint8Array.from(atob('{encoded}'), c => c.charCodeAt(0))))"
)
script = (
'tell application "Google Chrome" '
'to tell active tab of front window '
f"to execute javascript {wrapped!r}"
)
return run_applescript(script)

